import java.lang.Integer;
import java.text.DateFormat;
import java.text.ParseException;
import java.text.SimpleDateFormat;
import java.util.ArrayList;
import java.util.Date;
import java.util.Iterator;
import java.util.List;

import org.apache.log4j.Level;
import org.apache.log4j.Logger;

import sailpoint.object.Filter;
import sailpoint.object.Link;
import sailpoint.object.*;
import sailpoint.object.QueryOptions;
import sailpoint.tools.GeneralException;
import sailpoint.tools.Util;

Logger log = Logger.getLogger("com.test.report");

log.debug("QueryParameter: Enter Test Report");

QueryOptions qo = new QueryOptions(); 

qo.addFilter(Filter.eq("application.name", "HR System - Employees"));

Iterator iterator1 = context.search(Link.class, qo);

HashMap map1 = new HashMap();
if (iterator1 != null) {
while (iterator1.hasNext()) {

Link lnk = (Link) iterator1.next();
Identity id = lnk.getIdentity();
map1.put(id.getId(),lnk);

}
}

QueryOptions qo1 = new QueryOptions(); 

qo1.addFilter(Filter.eq("application.name", "HR System - Employees"));


Iterator iterator2 = context.search(Link.class, qo1);

HashMap map2 = new HashMap();
if (iterator2 != null) {
while (iterator2.hasNext()) {

Link lnk = (Link) iterator2.next();
Identity id = lnk.getIdentity();
map2.put(id.getId(),lnk);
}
}


HashMap greater = map1;
HashMap smaller = map2;

if(map2.size() > map1.size()){
greater = map2;
smaller = map1;
}
Set identitie = new HashSet();
for (Map.Entry entry: greater.entrySet()){
for (Map.Entry entry1: smaller.entrySet()){
if(entry.getKey() == entry1.getKey()){
identitie.add(entry.getKey());
}
else {
if(entry.getKey() != null){
identitie.add(entry.getKey());
}
if(entry1.getKey() != null){
identitie.add(entry1.getKey());
}
}
}
}


if(identitie.size() > 0) {
log.debug("In scope terminated with active= accounts count: " + identitie.size());
}
else {
identitie.add("no match found"); //need to pass dummy value that will not match any id if there are no active accounts that are terminated
}

queryOptions.addFilter(Filter.in("id", identitie));

return queryOptions;

